class LUPrefix {
public:
    LUPrefix(int n) {
        lastUploaded = 0;
    }

    void upload(int video) {
        if (video > lastUploaded + 1) {
            lastUploaded = video;
        }
    }

    int longest() {
        return lastUploaded;
    }
private:
    int lastUploaded;
};
